com.mirth.connect.plugins.javascriptstep.script:
if (msg['Parameters']['hosnum'].toString()) {
    tmp['QPD']['QPD.3']['QPD.3.1'] = msg['Parameters']['hosnum'].toString();
} else {
    tmp['QPD']['QPD.3']['QPD.3.1'] = msg['Parameters']['nhsnum'].toString();
}

var xmlrequest = msg['Parameters']['xmlrequest'].toString();

var segments = {
	'patient': 'PID',
	'patient_visit': 'PV1',
	'patient_visit_additional': 'PV2',
	'diagnosis': 'DG1',
	'procedures': 'PR1',
	'obxs': 'OBX',
	'uk_additional': 'ZU1',
	'event_type': 'EVN',
};

var HL7mappings = {
	'PID': {
	     'patient_number': 'PID.2.1',
	     'assigning_authority': 'PID.2.4',
	     'identifer_type_code': 'PID.2.5',
	     'nhs_number': 'PID.3.1',
	     'nhs_assigning_authority': 'PID.3.4',
	     'nhs_identifier_type_code': 'PID.3.5',
	},
	'PV1': {
		'patient_class':'PV1.2',
     	'point_of_care':'PV1.3.1',
     	'room':'PV1.3.2',
     	'clinician':'PV1.7.1',
     	'admit_source':'PV1.14',
     	'visit_number':'PV1.19',
     	'discharge_status':'PV1.36.1',
     	'discharge_to_location':'PV1.37.1',
     	'discharge_facility':'PV1.42.4',
     	'discharge_datetime':'PV1.45',
     },
	'PV2': {
		'chief_complaint_code': 'PV2.3.1',
     	'chief_complaint_description':'PV2.3.2',
     	'chief_alternative_identifier': 'PV2.3.4',
     	'name_of_alternative_coding_system':'PV2.3.6',
     	'referral_source_code':'PV2.13',
     	'patient_status_code':'PV2.24',
     	'admission_level_alternative_identifier':'PV2.40.4',
     	'name_of_alternative_coding_system':'PV2.40.6',
	},
	'DG1': {
	     'identifier':'DG1.1',
	     'diagnosis_coding_method':'DG1.2',
	     'diagnosis_code_identifier':'DG1.3.1',
	     'diagnosis_code_text':'DG1.3.2',
	     'diagnosis_code_name_of_coding_system':'DG1.3.3',
	     'diagnosis_description':'DG1.4',
	     'diagnosis_date_time':'DG1.5',
	     'diagnosis_type':'DG1.6',
	     'clinician_id_number':'DG1.16.1',
	     'clinician_family_name':'DG1.16.2',
	     'clinician_given_name':'DG1.16.3',
	     'clinician_prefix':'DG1.16.6',
	     'clinician_degree':'DG1.16.7',
	},
	'PR1': {
	     'identifier':'PR1.1',
	     'procedure_coding_method':'PR1.2',
	     'procedure_code_identifier':'PR1.3.1',
	     'procedure_code_text':'PR1.3.2',
	     'procedure_code_name_of_coding_system':'PR1.3.3',
	     'procedure_date_time':'PR1.5',
	     'procedure_functional_type':'PR1.6',
	     'clinician_id_number':'PR1.11.1',
	     'clinician_family_name':'PR1.11.2',
	     'clinician_given_name':'PR1.11.3',
	     'clinician_prefix':'PR1.11.6',
	     'clinician_degree':'PR1.11.7',
	},
	'OBX': {	 
		'id':'OBX.1',
		'code':'OBX.2',
		'type':'OBX.3',
		'OBX.4':'OBX.4',
		'value':'OBX.5',
	},
	'ZU1': {
	     'identifier':'ZU1.13.1',
     	'text':'ZU1.13.2',
     	'name_of_coding_system':'ZU1.13.3',
	},
	'EVN': {
	     'event_type_code':'EVN.1',
     	'recorded_date_time':'EVN.2',
     	'date_time_planned_event':'EVN.3',
     	'event_reason_code':'EVN.4',
     	'operator_id':'EVN.5',
     	'event_occured':'EVN.6',
	},
};

function renderSegment(segment, i) {
	for(index in segment) {
		item = segment[index];
		var str_level = HL7mappings[segments[segmentcode]][index].split('.');
		var hl7value = "";
		if(!Array.isArray(item) && typeof item === 'object' && item !== null) {
			var count2 = 0;
			for(var index2 in item) {
					var hl7value2 = "";
					var item2 = item[index2];
					if(!Array.isArray(item2) && typeof item2 === 'object' && item2 !== null) {
						for (var item3 in item2) { 
							if(hl7value2.length>0) {
								hl7value2 = hl7value2 + " :: ";
							}
							if(item3 != "event_id") {
								hl7value2 = hl7value2 + item2[item3];
							}
						}
					} else {
						if(item2 !== null) {
							hl7value2 = item2;
						}
					}
					if (count2 > 0) {
						hl7value = hl7value+"~";
					}
					hl7value = hl7value + hl7value2;
					count2++;
				};
		} else {
			if(item !== null) {
				hl7value = item;
			}
		}
		if(str_level.length==1) {
			if(item != null) {
				tmp[segments[segmentcode]][i] = hl7value;
			}
		} else if(str_level.length==2) {
			tmp[segments[segmentcode]][i][str_level[0]+'.'+str_level[1]] = hl7value;
		} else if(str_level.length==3) {
			tmp[segments[segmentcode]][i][str_level[0]+'.'+str_level[1]][str_level[0]+'.'+str_level[1]+'.'+str_level[2]] = hl7value;
		} else if(str_level.length==4) {
			tmp[segments[segmentcode]][i][str_level[0]+'.'+str_level[1]][str_level[0]+'.'+str_level[1]+'.'+str_level[2]][str_level[0]+'.'+str_level[1]+'.'+str_level[2]+'.'+str_level[3]] = hlvalue;
		}
	}
}

if (xmlrequest) {
	var json = JSON.parse(XmlUtil.toJson(xmlrequest));
	json = json['root'];
	tmp['MSH']['MSH.9']['MSH.9.1'] = 'ADT';
	prevsegmentcode = "";
	for(segmentcode in json) {
		segment = json[segmentcode];
		if(segmentcode=="message_type") {

			tmp['MSH']['MSH.9']['MSH.9.2'] = segment;
		} else {		
			if(Object.prototype.toString.call(segment) == "[object Object]") {
				createSegment(segments[segmentcode],tmp);
				renderSegment(segment,0);
			} else {
				si_counter = 0;
				for(segmentindex in segment) {
					if(segment[segmentindex] != null) {
						createSegment(segments[segmentcode],tmp,si_counter);
						renderSegment(segment[segmentindex],si_counter);
						si_counter++;
					}
				}
			}
		}
	};

} else {
	tmp['MSH']['MSH.9']['MSH.9.1'] = 'QBP';
	tmp['MSH']['MSH.9']['MSH.9.2'] = 'Q21';
}

//OBX|1|ST|OUTCOME||Interim Outcome - Unstable//OBX|14|ST|INTERIMOUTCOME||Unstable 

var interim = false;

for (obx in tmp['OBX']) {
	if(tmp['OBX'][obx]['OBX.3'].toString() == 'INTERIMOUTCOME' && tmp['OBX'][obx]['OBX.5'].toString() != '') {
		logger.info('INTERIM: '+ tmp['OBX'][obx]['OBX.3'] + ' {' + tmp['OBX'][obx]['OBX.5'] + '}')
		interim = true;
	}
}

if (interim) {
	for (obx in tmp['OBX']) {
		if(tmp['OBX'][obx]['OBX.3'].toString() == 'OUTCOME') {
			//tmp['OBX'][obx]['OBX.5'] = '';
			delete tmp['OBX'][obx];
			break;
		}
	}
	var i = 1;
	for (obx in tmp['OBX']) {
		tmp['OBX'][obx]['OBX.1'] = i++;
	}
}

//Final Outcome - Normal:Discharge
//Final Outcome - Stable 18 months:18 months
//Final Outcome - Stable 12 months:12 months
//Final Outcome - Low Risk:6 months
//Final Outcome - Unstable Prescription Change:2 months
//Final Outcome - Unstable:6 weeks
//Final Outcome - High Risk - Newmedica:2 Days
//Final Outcome - High Risk - A&E:Discharge

var timetonextappt = "";
var specialty = "";
var appointmenttype = "";

for (obx in tmp['OBX']) {

	if(tmp['OBX'][obx]['OBX.3'].toString() == 'OUTCOME') {

		var values = tmp['OBX'][obx]['OBX.5'].toString().split('~');
		var primary_outcome = values[0];

		logger.info('Primary outcome: ' + primary_outcome);

		if(primary_outcome == 'Final Outcome - Normal') {
			timetonextappt = 'Discharge';
		} else if(primary_outcome.substr(0,22) == 'Final Outcome - Stable') {
			timetonextappt = primary_outcome.substring(25);
		} else if(primary_outcome.toString() == 'Final Outcome - Low Risk') {
			timetonextappt = '6 months';
		} else if(primary_outcome.toString() == 'Final Outcome - Unstable Prescription Change') {
			timetonextappt = '2 months';
		} else if(primary_outcome.toString() == 'Final Outcome - Unstable') {
			timetonextappt = '6 weeks';
		} else if(primary_outcome.toString() == 'Final Outcome - High Risk - Newmedica') {
			timetonextappt = '2 Days';
		} else if(primary_outcome.toString() == 'Final Outcome - High Risk - A\\T\\E') {
			timetonextappt = 'Discharge';
		}

		if(primary_outcome.toString().substr(0,13) == 'Final Outcome') {
			//OBX|3|ST|SPECIALTY||Glaucoma Monitoring
			//OBX|6|ST|APPOINTMENTTYPE||NHS
			specialty = 'Glaucoma Monitoring';
			appointmenttype = 'NHS';

		}
	}
}

if (timetonextappt != "") {
	for (obx in tmp['OBX']) {
		if(tmp['OBX'][obx]['OBX.3'].toString() == 'TIMETONEXTAPPT') {
			values = tmp['OBX'][obx]['OBX.5'].toString().split('~');
			values[0] = timetonextappt;
			tmp['OBX'][obx]['OBX.5'] = values.join('~');
		}
		if(specialty != "" && tmp['OBX'][obx]['OBX.3'].toString() == 'SPECIALTY') {
			values_spec = tmp['OBX'][obx]['OBX.5'].toString().split('~');
			values_spec[0] = specialty;
			tmp['OBX'][obx]['OBX.5'] = values_spec.join('~');
		}
		if(appointmenttype != "" && tmp['OBX'][obx]['OBX.3'].toString() == 'APPOINTMENTTYPE') {
			values_apttype = tmp['OBX'][obx]['OBX.5'].toString().split('~');
			values_apttype[0] = appointmenttype;
			tmp['OBX'][obx]['OBX.5'] = values_apttype.join('~');
		}

	}
}

for (obx in tmp['OBX']) {
	if(tmp['OBX'][obx]['OBX.3'].toString() == 'INTERIMOUTCOME'
		&& tmp['OBX'][obx]['OBX.5'].toString() == '') {
		//tmp['OBX'][obx]['OBX.5'] = '';
		delete tmp['OBX'][obx];
		break;
	}
}

var i = 1;
for (obx in tmp['OBX']) {
	tmp['OBX'][obx]['OBX.1'] = i++;
}

com.mirth.connect.plugins.javascriptrule.script:
if(msg['Parameters']['hosnum'].toString() || msg['Parameters']['nhsnum'].toString() || msg['Parameters']['xmlrequest'].toString()) {
	return true;
}

return false;

var interim = false;

for (obx in msg['OBX']) {

	if(msg['OBX'][obx]['OBX.3']['OBX.3.1'].toString() == 'INTERIMOUTCOME' && msg['OBX'][obx]['OBX.5']['OBX.5.1'].toString() != '') {
		interim = true;
	}
}

logger.info('Interim: '+interim);

return interim;

properties.script:
var destination = responseMap.get('Send Q21');
var responseMessage = destination.getMessage();
var Xmsg = new XML(SerializerFactory.getSerializer('HL7V2').toXML(responseMessage));

var sResp = ResponseFactory.getSentResponse(Xmsg)

responseMap.put('K21ResponseXML', sResp);

